import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"崩溃报告","description":"学习如何处理崩溃报告以及如何阅读它们。","frontmatter":{"title":"崩溃报告","description":"学习如何处理崩溃报告以及如何阅读它们。","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"zh_cn/1.20.4/players/troubleshooting/crash-reports.md","filePath":"versions/1.20.4/translated/zh_cn/players/troubleshooting/crash-reports.md","lastUpdated":1766341111000}`);var a={name:`zh_cn/1.20.4/players/troubleshooting/crash-reports.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">崩溃报告 <a class="header-anchor" href="#h1" aria-label="Permalink to “崩溃报告”">​</a></h1><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>如果你在查找崩溃原因时遇到困难，可以在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 或 <code>#server-admin-support</code> 频道中寻求帮助。</p></div><p>崩溃报告是解决游戏或服务器问题的重要部分。 它包含大量关于崩溃的信息，可以帮助你找到崩溃的原因。 它包含大量关于崩溃的信息，可以帮助你找到崩溃的原因。</p><h2 id="寻找崩溃报告" tabindex="-1">寻找崩溃报告 <a class="header-anchor" href="#寻找崩溃报告" aria-label="Permalink to “寻找崩溃报告”">​</a></h2><p>它们位于游戏根目录中的 <code>crash-reports</code> 文件夹中。 如果是服务器，它们会存储在服务器实例根目录下的 <code>crash-reports</code> 文件夹中。 如果是服务器，它们会存储在服务器实例根目录下的 <code>crash-reports</code> 文件夹中。</p><p>对于第三方启动器，你应该参考其文档，了解在哪里可以找到崩溃报告。</p><p>崩溃报告可能在以下位置被找到：</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-23" id="tab-24" checked><label data-title="Windows" for="tab-24">Windows</label><input type="radio" name="group-23" id="tab-25"><label data-title="macOS" for="tab-25">macOS</label><input type="radio" name="group-23" id="tab-26"><label data-title="Linux" for="tab-26">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\crash-reports</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/crash-reports</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/crash-reports</span></span></code></pre></div></div></div><h2 id="阅读崩溃报告" tabindex="-1">阅读崩溃报告 <a class="header-anchor" href="#阅读崩溃报告" aria-label="Permalink to “阅读崩溃报告”">​</a></h2><p>崩溃报告的篇幅很长，读起来十分费解。 但无论怎样，它包含着大量关于崩溃的信息，可以帮助你找到崩溃的原因，因此你不得不阅读它。 但无论怎样，它包含着大量关于崩溃的信息，可以帮助你找到崩溃的原因，因此你不得不阅读它。</p><p>在本指南中，我们将以 <a href="https://github.com/FabricMC/fabric-docs/blob/main/public/assets/players/crash-report-example.log" target="_blank" rel="noreferrer">该崩溃报告</a> 为例。</p><h3 id="崩溃报告的各部分" tabindex="-1">崩溃报告的各部分 <a class="header-anchor" href="#崩溃报告的各部分" aria-label="Permalink to “崩溃报告的各部分”">​</a></h3><p>崩溃报告由几个部分组成，每个部分都用标题来分隔：</p><ul><li><code>---- Minecraft Crash Report ----</code>，报告摘要部分。 该部分包含导致崩溃的主要错误原因、发生时间和相关堆栈跟踪。 这是崩溃报告中最重要的部分，因为堆栈跟踪通常会提及到导致崩溃的模组。 该部分包含导致崩溃的主要错误原因、发生时间和相关堆栈跟踪。 这是崩溃报告中最重要的部分，因为堆栈跟踪通常会提及到导致崩溃的模组。</li><li><code>-- Last Reload --</code>，除非崩溃发生在资源重载过程中 (<kbd>F3</kbd>+<kbd>T</kbd>) ，否则这部分并没有什么用处。 该部分将包含上次重载的发生时间，以及重载过程中出现的任何错误的相关堆栈跟踪。 这些错误通常是由资源包引起的，可以忽略不计，除非它们导致游戏出现问题。</li><li><code>-- System Details --</code>，本部分包含有关设备的信息，如操作系统、Java 版本和分配给游戏的内存量。 该部分有助于确定你使用的 Java 版本是否正确，以及是否为游戏分配了足够的内存。 该部分有助于确定你使用的 Java 版本是否正确，以及是否为游戏分配了足够的内存。 <ul><li>在此部分中，Fabric 将插入一些自定义内容，其标题为 <code>Fabric Mods:</code>，后面是所有已安装模组的列表。 该部分有助于判断模组之间是否有可能发生冲突。 该部分有助于判断模组之间是否有可能发生冲突。</li></ul></li></ul><h3 id="分解崩溃报告" tabindex="-1">分解崩溃报告 <a class="header-anchor" href="#分解崩溃报告" aria-label="Permalink to “分解崩溃报告”">​</a></h3><p>既然我们已经知道崩溃报告的每个部分代表着什么，我们就可以开始分解崩溃报告并找出崩溃原因。</p><p>利用上面链接的崩溃示例，我们可以分析崩溃报告并找到崩溃原因，包括导致崩溃的模组。</p><p><code>-- Last Reload --</code>，除非崩溃发生在资源重载过程中 (<kbd>F3</kbd>+<kbd>T</kbd>) ，否则这部分并没有什么用处。 该部分将包含上次重载的发生时间，以及重载过程中出现的任何错误的相关堆栈跟踪。 这些错误通常是由资源包引起的，可以忽略不计，除非它们导致游戏出现问题。 在这种情况下，<code>---- Minecraft Crash Report ----</code> 部分中的堆栈跟踪最为重要，因为它包含导致崩溃的主要错误。 在这里，错误为<code>java.lang.NullPointerException: Cannot invoke &quot;net.minecraft.class_2248.method_9539()&quot; because &quot;net.minecraft.class_2248.field_10540&quot; is null</code>.</p><p>由于堆栈跟踪中提到了大量的模组，因此很难指认崩溃&quot;凶手&quot;，不过，首先要做的是查找导致崩溃的部分。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>at snownee.snow.block.ShapeCaches.get(ShapeCaches.java:51)</span></span>
<span class="line"><span>at snownee.snow.block.SnowWallBlock.method_9549(SnowWallBlock.java:26) // [!code focus]</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>at me.jellysquid.mods.sodium.client.render.chunk.compile.pipeline.BlockOcclusionCache.shouldDrawSide(BlockOcclusionCache.java:52)</span></span>
<span class="line"><span>at link.infra.indium.renderer.render.TerrainBlockRenderInfo.shouldDrawFaceInner(TerrainBlockRenderInfo.java:31)</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>在这里，导致崩溃的模组是 <code>snownee</code>，因为它是堆栈跟踪中提到的第一个模组。</p><p>不过，从堆栈追踪中提到的模组数量来看，这可能意味着模组之间存在一些兼容性问题，导致崩溃的模组可能并不是出错的模组。 在这种情况下，最好向模组作者报告崩溃情况，让他们调查崩溃原因。 在这种情况下，最好向模组作者报告崩溃情况，让他们调查崩溃原因。</p><h2 id="mixin崩溃" tabindex="-1">Mixin崩溃 <a class="header-anchor" href="#mixin崩溃" aria-label="Permalink to “Mixin崩溃”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Mixin 是一种修改游戏的方式，使模组无需破坏性的直接修改游戏的源代码。 它被许多模组使用，对于开发者来说是一款非常强大的工具。 它被许多模组使用，对于开发者来说是一款非常强大的工具。</p></div><p>当有 Mixin 引起的崩溃时，通常会在堆栈跟踪中提到该 Mixin 类以及该 Mixin 类修改的类。</p><p>方法 Mixin 的标识 <code>mod-id$handlerName</code> 将被包含在堆栈跟踪中，其中 <code>mod-id</code> 是模组的 ID，而 <code>handlerName</code> 是 Mixin 处理部分的名称。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>... net.minecraft.class_2248.method_3821$$$mod-id$handlerName() ... // [!code focus]</span></span></code></pre></div><p>你可以使用此信息找到导致崩溃的模组，并向模组作者报告崩溃情况。</p><h2 id="如何处理崩溃报告" tabindex="-1">如何处理崩溃报告 <a class="header-anchor" href="#如何处理崩溃报告" aria-label="Permalink to “如何处理崩溃报告”">​</a></h2><p>处理崩溃报告的最佳方法是将其上传到在线粘贴板网站，然后在问题追踪处或通过某种联系方式 (Discord 等) 向修改器作者提供崩溃报告网站链接。</p><p>这可以让模组作者调查崩溃原因、重现崩溃状况并解决导致崩溃的问题。</p><p>常用的崩溃报告粘贴网站有：</p><ul><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,33)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};